1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[1]])).toEqual([]);
10	  });
11	  it("should return empty grid for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has exactly 2 live neighbors", () => {
15	    expect(nextGeneration([[1, 1, 1]])).toEqual([[1], [1], [1]]);
16	  });
17	  it("should keep a live cell alive when it has exactly 3 live neighbors", () => {
18	    // 2x2 block: each live cell has exactly 3 live neighbors, all should survive
19	    expect(nextGeneration([[1, 1], [1, 1]])).toEqual([[1, 1], [1, 1]]);
20	  });
21	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
22	    // Center cell has 4 live neighbors (up, down, left, right) - dies from overpopulation
23	    expect(nextGeneration([[0, 1, 0], [1, 1, 1], [0, 1, 0]])).toEqual([[1, 1, 1], [1, 0, 1], [1, 1, 1]]);
24	  });
25	  it("should reproduce a dead cell with exactly 3 live neighbors", () => {
26	    // Dead cell at (0,0) with exactly 3 live neighbors: (0,1), (1,0), (1,1)
27	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([[1, 1], [1, 1]]);
28	  });
29	  it("should transform a blinker (3 cells in a row) to next generation (3 cells in a column)", () => {
30	    // Horizontal blinker: 3 cells in a row -> vertical blinker: 3 cells in a column
31	    expect(nextGeneration([[1, 1, 1]])).toEqual([[1], [1], [1]]);
32	  });
33	  it.todo("should keep a block (2x2 square) unchanged as a still life");
34	});
