1	type Grid = number[][];
2	
3	const isLiveCell = (cell: number): boolean => cell === 1;
4	
5	const countNeighbors = (grid: Grid, row: number, col: number): number => {
6	  let count = 0;
7	  for (let r = row - 1; r <= row + 1; r++) {
8	    for (let c = col - 1; c <= col + 1; c++) {
9	      if (r === row && c === col) continue;
10	      if (r >= 0 && r < grid.length && c >= 0 && c < grid[r].length) {
11	        count += grid[r][c];
12	      }
13	    }
14	  }
15	  return count;
16	};
17	
18	const getNextCellState = (grid: Grid, cell: number, row: number, col: number): number => {
19	  const neighbors = countNeighbors(grid, row, col);
20	  const alive = isLiveCell(cell);
21	  const survives = alive && (neighbors === 2 || neighbors === 3);
22	  const isReborn = !alive && neighbors === 3;
23	  return survives || isReborn ? 1 : 0;
24	};
25	
26	const padGrid = (grid: Grid): Grid => {
27	  const cols = grid[0]?.length ?? 0;
28	  const emptyRow = Array(cols + 2).fill(0);
29	  const paddedRows = grid.map(row => [0, ...row, 0]);
30	  return [emptyRow, ...paddedRows, emptyRow];
31	};
32	
33	const trimGrid = (grid: Grid): Grid => {
34	  let trimmed = grid.filter(row => row.some(isLiveCell));
35	  if (trimmed.length === 0) return [];
36	  const cols = trimmed[0].length;
37	  let minCol = cols;
38	  let maxCol = -1;
39	  for (const row of trimmed) {
40	    for (let c = 0; c < cols; c++) {
41	      if (isLiveCell(row[c])) {
42	        if (c < minCol) minCol = c;
43	        if (c > maxCol) maxCol = c;
44	      }
45	    }
46	  }
47	  return trimmed.map(row => row.slice(minCol, maxCol + 1));
48	};
49	
50	export function nextGeneration(grid: Grid): Grid {
51	  if (grid.length === 0) return [];
52	
53	  const padded = padGrid(grid);
54	
55	  const nextGrid: Grid = padded.map((row, r) =>
56	    row.map((cell, c) => getNextCellState(padded, cell, r, c))
57	  );
58	
59	  return trimGrid(nextGrid);
60	}
